import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is amortization?", a: "Amortization is the process of paying off a loan through scheduled payments. Each payment is split between interest and principal until the balance reaches zero." },
  { q: "How do you read an amortization schedule?", a: "Read each row as one payment period. The table shows the payment amount, how much goes to interest, how much reduces principal, total paid so far, and the remaining balance." },
  { q: "Why do early payments go mostly to interest?", a: "Interest is charged on the remaining balance. Because the balance is highest at the start, early payments usually include more interest and less principal." },
  { q: "How does making extra payments affect amortization?", a: "Extra principal payments reduce the balance faster, which can lower total interest and shorten the loan payoff timeline." },
  { q: "What is negative amortization?", a: "Negative amortization happens when a payment is too small to cover the interest due, causing the loan balance to increase instead of decrease." },
];

const money = (value: number, digits = 2) => formatCurrencyValue(value, { maximumFractionDigits: digits });

function monthlyPayment(principal: number, annualRate: number, months: number) {
  if (principal <= 0 || months <= 0) return 0;
  const rate = annualRate / 100 / 12;
  if (rate === 0) return principal / months;
  const factor = Math.pow(1 + rate, months);
  return principal * rate * factor / (factor - 1);
}

function buildSchedule(principal: number, annualRate: number, termYears: number) {
  const months = Math.max(1, Math.round(termYears * 12));
  const rate = annualRate / 100 / 12;
  const payment = monthlyPayment(principal, annualRate, months);
  let balance = principal;
  return Array.from({ length: months }, (_, index) => {
    const month = index + 1;
    const interest = balance * rate;
    const principalPaid = Math.min(balance, payment - interest);
    balance = Math.max(0, balance - principalPaid);
    return { month, payment, principal: principalPaid, interest, totalPaid: payment * month, balance };
  });
}

export default function AmortizationCalculator() {
  useCurrencyVersion();
  const [loanAmount, setLoanAmount] = useState(200000);
  const [interestRate, setInterestRate] = useState(6);
  const [termYears, setTermYears] = useState(30);

  const schedule = useMemo(() => buildSchedule(loanAmount, interestRate, termYears), [loanAmount, interestRate, termYears]);
  const monthly = schedule[0]?.payment || 0;
  const totalPayment = monthly * Math.max(1, termYears * 12);
  const totalInterest = Math.max(0, totalPayment - loanAmount);

  const comparisonBase = useMemo(() => buildSchedule(200000, 6, 30), []);
  const comparisonRows = [1, 5, 10, 15, 20, 25, 30].map((year) => {
    const rows = comparisonBase.slice((year - 1) * 12, year * 12);
    const annualPrincipal = rows.reduce((sum, row) => sum + row.principal, 0);
    const annualInterest = rows.reduce((sum, row) => sum + row.interest, 0);
    const annualPayment = rows.reduce((sum, row) => sum + row.payment, 0);
    return { year, annualPrincipal, annualInterest, annualPayment, balance: rows[rows.length - 1]?.balance || 0 };
  });

  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  return (
    <>
      <SEOHead title="Free Amortization Calculator Online - Calculate Full Loan Amortization Schedule Instantly | CalcHive" description="Free online amortization calculator. Calculate complete amortization schedule for any loan with monthly principal, interest and balance breakdown instantly. 100% free, no signup required." canonical="/amortization-calculator" keywords="free amortization calculator, loan amortization schedule calculator free, mortgage amortization calculator free online, amortization table calculator free, monthly amortization calculator free" category="Financial Calculators" breadcrumbName="Free Amortization Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Amortization Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Calculate a complete monthly amortization table with principal, interest, total paid, and remaining balance for any loan.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Loan amount</label><input type="number" min="0" value={loanAmount} onChange={(e) => setLoanAmount(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" min="0" step="0.1" value={interestRate} onChange={(e) => setInterestRate(Number(e.target.value))} className={inputClass} /></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Loan term (years)</label><input type="number" min="1" value={termYears} onChange={(e) => setTermYears(Number(e.target.value))} className={inputClass} /></div>
          </div>
          <motion.div key={`${loanAmount}-${interestRate}-${termYears}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Monthly Payment</p>
              <p className="text-5xl sm:text-6xl font-black text-white tracking-tight" data-testid="result-amortization">{money(monthly)}</p>
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4">
              {[["Total Payments", totalPayment], ["Total Interest", totalInterest], ["Payments", schedule.length]].map(([label, value]) => (
                <div key={label as string} className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground font-medium mb-1">{label as string}</p><p className="text-lg font-extrabold text-foreground">{typeof value === "number" && label !== "Payments" ? money(value) : value}</p></div>
              ))}
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate a Full Loan Amortization Schedule for Free</h2>
          <p className="text-muted-foreground leading-relaxed">This loan amortization schedule calculator free uses the standard monthly payment formula, then applies each monthly interest charge to the remaining balance.</p>
          <h2 className="text-2xl font-bold text-foreground">How to Read and Use an Amortization Table</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Amortization Breakdown on $200,000 Mortgage at 6%</caption><thead className="bg-muted/60"><tr>{["Year", "Annual Principal", "Annual Interest", "Annual Payment", "Remaining Balance"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{comparisonRows.map((row) => <tr key={row.year} className="hover:bg-muted/30"><td className="py-2.5 px-3 font-semibold text-foreground">{row.year}</td><td className="py-2.5 px-3 text-emerald-600 dark:text-emerald-400">{money(row.annualPrincipal)}</td><td className="py-2.5 px-3 text-red-600 dark:text-red-400">{money(row.annualInterest)}</td><td className="py-2.5 px-3">{money(row.annualPayment)}</td><td className="py-2.5 px-3">{money(row.balance)}</td></tr>)}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Mortgage Amortization Tool for Everyone</h2>
          <div className="overflow-x-auto"><table className="w-full text-xs border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Complete Monthly Amortization Schedule</caption><thead className="bg-muted/60"><tr>{["Month", "Payment", "Principal", "Interest", "Total Paid", "Remaining Balance"].map((h) => <th key={h} className="text-right py-3 px-2 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{schedule.map((row) => <tr key={row.month} className="hover:bg-muted/30"><td className="py-2 px-2 text-right font-semibold">{row.month}</td><td className="py-2 px-2 text-right">{money(row.payment)}</td><td className="py-2 px-2 text-right text-emerald-600 dark:text-emerald-400">{money(row.principal)}</td><td className="py-2 px-2 text-right text-red-600 dark:text-red-400">{money(row.interest)}</td><td className="py-2 px-2 text-right">{money(row.totalPaid)}</td><td className="py-2 px-2 text-right">{money(row.balance)}</td></tr>)}</tbody></table></div>
        </section>

        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/amortization-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


